export const code = async (inputs) => {
  const { elasticPool, priceList } = inputs;

  const items = Array.isArray(priceList)
    ? priceList
    : Array.isArray(priceList?.Items)
      ? priceList.Items
      : [];

  const resourceId = elasticPool?.id;
  const location = elasticPool?.location;
  const sku = elasticPool?.sku || {};

  const capacity = Number(sku.capacity || 0);
  const tier = sku.tier || elasticPool?.edition;
  const family = sku.family;
  const zoneRedundant = elasticPool?.zoneRedundant === true;

  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/[_-]/g, "")
      .replace(/\s+/g, "")
      .trim();

  const tierCodeMap = {
    generalpurpose: "GP",
    businesscritical: "BC",
    hyperscale: "HS"
  };

  const tierTextMap = {
    generalpurpose: "General Purpose",
    businesscritical: "Business Critical",
    hyperscale: "Hyperscale"
  };

  const tierKey = normalize(tier);
  const tierCode = tierCodeMap[tierKey] || "";
  const tierText = tierTextMap[tierKey] || tier;

  const expectedArmSkuName = `SQLDB_${tierCode}_Compute_${family}_${capacity}`;
  const expectedSkuName = zoneRedundant
    ? `${capacity} vCore Zone Redundancy`
    : `${capacity} vCore`;

  const expectedMeterName = zoneRedundant
    ? "Zone Redundancy vCore"
    : "vCore";

  const priceItem = items.find((p) => {
    if (p.type !== "Consumption") return false;
    if (p.serviceName !== "SQL Database") return false;
    if (p.unitOfMeasure !== "1 Hour") return false;
    if (p.meterName !== expectedMeterName) return false;
    if (p.armSkuName !== expectedArmSkuName) return false;
    if (p.skuName !== expectedSkuName) return false;

    if (!p.productName?.includes("Single/Elastic Pool")) return false;
    if (!p.productName?.includes(tierText)) return false;
    if (!p.productName?.includes(`Compute ${family}`)) return false;

    return true;
  });

  if (!priceItem || typeof priceItem.retailPrice !== "number") {
    return {
      resourceId,
      location,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  return {
    resourceId,
    location,
    dailyPricing: priceItem.retailPrice * 24,
    currency: priceItem.currencyCode || "USD"
  };
};

export const code = async (inputs) => {
  const metrics = inputs?.metrics;
  if (!Array.isArray(metrics) || metrics.length === 0) return 0;

  for (const metric of metrics) {
    if (!Array.isArray(metric?.timeseries)) continue;

    for (const series of metric.timeseries) {
      if (!Array.isArray(series?.data)) continue;

      for (const point of series.data) {
        const value = point?.maximum;
        if (typeof value === 'number' && value > 0) {
          return value;
        }
      }
    }
  }

  return 0;
};

